use std::cmp::Ordering;

// Monomorphised per (T, F): fast, inlinable, but more copies
fn my_sort<T, F: Fn(&T, &T) -> Ordering>(slice: &mut [T], cmp: F) {
    for i in 1..slice.len() {
        let mut j = i;
        while j > 0 && cmp(&slice[j-1], &slice[j]) == Ordering::Greater {
            slice.swap(j-1, j);
            j -= 1;
        }
    }
}

// dyn version: single compiled copy, indirect call
fn my_sort_dyn<T>(slice: &mut [T], cmp: &dyn Fn(&T, &T) -> Ordering) {
    for i in 1..slice.len() {
        let mut j = i;
        while j > 0 && cmp(&slice[j-1], &slice[j]) == Ordering::Greater {
            slice.swap(j-1, j);
            j -= 1;
        }
    }
}

fn main() {
    let mut v = vec![3i32, 1, 4, 1, 5, 9, 2, 6];

    // Each unique closure type = new monomorphised my_sort copy:
