use std::ops::Add;

// Recursive generic with same T — fine, compiles to one copy per T:
fn sum_recursive<T: Add<Output = T> + Default + Clone>(list: &[T]) -> T {
    match list {
        [] => T::default(),
        [head, tail @ ..] => head.clone() + sum_recursive(tail),
    }
}

// Iterative version — usually preferred (no stack risk for large slices):
fn sum_iter<T: Add<Output = T> + Default>(list: &[T]) -> T
where
    T: Copy,
{
    list.iter().copied().fold(T::default(), |acc, x| acc + x)
}

// The real monomorphization loop error occurs when T changes each call:
// fn wrap<T>(x: T) -> Wrapper<T> — calling wrap(wrap(wrap(...))) blows up types
// The compiler detects and rejects infinite monomorphization.
struct Wrapper<T>(T);

fn wrap_once<T>(x: T) -> Wrapper<T> { Wrapper(x) }

