    println!("{}", sum_recursive(&[1i32, 2, 3, 4, 5]));
    println!("{}", sum_iter(&[1.0f64, 2.0, 3.0]));
    let _w = wrap_once(wrap_once(42i32)); // Wrapper<Wrapper<i32>> — fine, bounded depth
