use std::iter;

// RPIT requires a single concrete type — use an enum or Box:
fn take_or_all<T: Clone>(v: &[T], n: Option<usize>) -> Box<dyn Iterator<Item = T> + '_> {
    match n {
        Some(n) => Box::new(v.iter().cloned().take(n)),
        None    => Box::new(v.iter().cloned()),
    }
}

// Zero-overhead alternative with a custom enum:
enum TakeOrAll<A, B> { Limited(A), All(B) }

impl<T, A: Iterator<Item = T>, B: Iterator<Item = T>> Iterator for TakeOrAll<A, B> {
    type Item = T;
    fn next(&mut self) -> Option<T> {
        match self {
            TakeOrAll::Limited(a) => a.next(),
            TakeOrAll::All(b)     => b.next(),
        }
    }
}

fn take_or_all_zero<T: Clone>(
    v: &[T],
    n: Option<usize>,
) -> TakeOrAll<iter::Take<iter::Cloned<std::slice::Iter<T>>>,
               iter::Cloned<std::slice::Iter<T>>> {
    match n {
        Some(n) => TakeOrAll::Limited(v.iter().cloned().take(n)),
        None    => TakeOrAll::All(v.iter().cloned()),
    }
}

fn main() {
    let data = vec![1i32, 2, 3, 4, 5];
    let v: Vec<i32> = take_or_all(&data, Some(3)).collect();
    println!("{:?}", v);
    let all: Vec<i32> = take_or_all_zero(&data, None).collect();
    println!("{:?}", all);
