fn stats<T: Copy + Into<f64>>(data: &[T]) -> (f64, f64) {
    assert!(!data.is_empty(), "stats requires at least one element");
    let n = data.len() as f64;
    let mean = data.iter().copied().map(f64::from).sum::<f64>() / n;
    let variance = data.iter().copied()
