use std::io::{self, Write, BufWriter};
use std::fmt;

// RULE: use generics when:
// 1. Performance is critical and inlining matters (hot paths)
// 2. The caller always knows the concrete type at compile time
// 3. You want to allow non-object-safe methods

fn write_fast<W: Write>(writer: &mut W, data: &[u8]) -> io::Result<usize> {
    // Monomorphised: BufWriter<File> gets its own optimised copy
    writer.write(data)
}

// RULE: use dyn Trait when:
// 1. The concrete type is chosen at runtime
// 2. You need a heterogeneous collection of trait objects
// 3. Binary size matters more than the vtable overhead
// 4. The function is in a library used by many downstream crates

fn write_any(writers: &mut [&mut dyn Write], data: &[u8]) -> io::Result<()> {
    for w in writers.iter_mut() {
        w.write_all(data)?;
    }
    Ok(())
}

fn log_and_format(v: &dyn fmt::Display) -> String {
    // dyn: caller might not know the type at compile time
    v.to_string()
}

fn main() -> io::Result<()> {
    let mut v1 = Vec::new();
    let mut v2 = Vec::new();
    write_any(&mut [&mut v1, &mut v2], b"hello");
    println!("{:?} {:?}",
        String::from_utf8(v1).unwrap(),
        String::from_utf8(v2).unwrap());
    println!("{}", log_and_format(&42i32));
    Ok(())
}

