// Each unique (A, B, C, F) tuple = one monomorphised copy
// 3 type params + 1 closure = potentially many copies in a large codebase

fn zip_map<A: Clone, B: Clone, C, F: Fn(A, B) -> C>(
    a: &[A], b: &[B], f: F,
) -> Vec<C> {
    a.iter().zip(b.iter()).map(|(x, y)| f(x.clone(), y.clone())).collect()
}

// To reduce copies: collapse to concrete types or use dyn:
fn zip_add_i32(a: &[i32], b: &[i32]) -> Vec<i32> {
    // Concrete — zero overhead, one copy:
    a.iter().zip(b.iter()).map(|(x, y)| x + y).collect()
}

