use std::sync::atomic::{AtomicU64, Ordering};
use std::sync::OnceLock;

// Each monomorphised copy of type_id_for::<T> gets its OWN static!
fn type_id_for<T>() -> u64 {
    // This static is PER MONOMORPHISED INSTANCE of the function:
    static ID: OnceLock<u64> = OnceLock::new();
    static COUNTER: AtomicU64 = AtomicU64::new(0);
    *ID.get_or_init(|| COUNTER.fetch_add(1, Ordering::SeqCst))
}

